import React, { useState } from 'react';

const App = () => {
  const [content, setContent] = useState([]);
  const [category, setCategory] = useState('All');

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="grid grid-cols-3 gap-4">
        {content.map((item) => (
          <div key={item.id} className="bg-white p-4 rounded shadow">
            <h2>{item.title}</h2>
            <p>{item.description}</p>
          </div>
        ))}
      </div>
      <button className="bg-[#411C56] text-white p-2 rounded" onClick={() => setCategory('All')}>All</button>
      <button className="bg-[#B7D7CD] text-white p-2 rounded" onClick={() => setCategory('Category 1')}>Category 1</button>
      <button className="bg-[#C06C88] text-white p-2 rounded" onClick={() => setCategory('Category 2')}>Category 2</button>
      <button className="bg-[#411C56] text-white p-2 rounded" onClick={() => setContent([])}>Clear</button>
    </div>
  );
};

export default App;
